import{_ as s,o as i,c as a,a2 as t}from"./chunks/framework.BfRM_mob.js";const c=JSON.parse('{"title":"On-disk Format","description":"","frontmatter":{},"headers":[],"relativePath":"reference/file-format.md","filePath":"reference/file-format.md","lastUpdated":1783734888000}'),n={name:"reference/file-format.md"};function o(l,e,h,d,r,p){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="on-disk-format" tabindex="-1">On-disk Format <a class="header-anchor" href="#on-disk-format" aria-label="Permalink to &quot;On-disk Format&quot;">​</a></h1><p>Everything wikimem persists is designed to be read (and mostly written) by humans. A complete memory directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memory/</span></span>
<span class="line"><span>├── preferences.md        ← source of truth (one file per category)</span></span>
<span class="line"><span>├── daily_life.md         ← source of truth</span></span>
<span class="line"><span>├── journal.jsonl         ← append-only audit log</span></span>
<span class="line"><span>├── vectors-000003.npy    ← derived: vector cache ([embed] only)</span></span>
<span class="line"><span>└── vectors.keys.jsonl    ← derived: cache key map ([embed] only)</span></span></code></pre></div><p><strong>Deletability rule of thumb:</strong> the <code>.md</code> files are the memory; everything else can be deleted at any time and rebuilds automatically (the journal is history — deleting it loses the audit trail but no memories; the BM25 index never even touches disk).</p><h2 id="category-files" tabindex="-1">Category files <a class="header-anchor" href="#category-files" aria-label="Permalink to &quot;Category files&quot;">​</a></h2><p>One markdown file per category, one <code>##</code> section per item:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># preferences</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## likes-the-sea</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">喜欢海边，提到过想去海边玩。[[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">daily_life:beach-trip-plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- wikimem: owner=user:xnne | source=conv_20260710 | ts=2026-07-10T03:00:00+00:00 --&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 手冲咖啡</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">只喝手冲咖啡，从不加糖。</span></span></code></pre></div><p>Serialized parts, in order per item: the <code>## name</code> heading, a blank line, the content (stored stripped), a blank line, and — only when any provenance field is set — the metadata comment.</p><h3 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h3><ul><li><strong>Category</strong> = filename stem = link prefix. Must match <code>[a-z0-9_][a-z0-9_-]*</code> (lowercase ASCII slug). Enforced on write.</li><li><strong>Item name</strong> = heading text = link target. Any language; whitespace runs collapse to one space; must not contain <code>[[</code>, <code>]]</code>, <code>:</code>, <code>|</code>, <code>#</code>. Enforced on write.</li></ul><h3 id="the-metadata-comment" tabindex="-1">The metadata comment <a class="header-anchor" href="#the-metadata-comment" aria-label="Permalink to &quot;The metadata comment&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!-- wikimem: owner=user:xnne | source=conv_20260710 | ts=2026-07-10T03:00:00+00:00 --&gt;</span></span></code></pre></div><ul><li>Fields are <code>key=value</code> pairs separated by <code>|</code>; recognized keys: <code>owner</code>, <code>source</code> (surfaced as <code>MemoryItem.source_conv</code>), <code>ts</code> (ISO-8601 UTC).</li><li>All fields are optional; the whole comment is omitted when empty.</li><li>Because <code>|</code> is the separator, a literal <code>|</code> inside an owner/source value is replaced with <code>/</code> at write time.</li></ul><h3 id="read-tolerance-hand-edits-welcome" tabindex="-1">Read tolerance (hand edits welcome) <a class="header-anchor" href="#read-tolerance-hand-edits-welcome" aria-label="Permalink to &quot;Read tolerance (hand edits welcome)&quot;">​</a></h3><p>Reading is deliberately liberal — these are guarantees, not accidents:</p><table tabindex="0"><thead><tr><th>you did this</th><th>wikimem does this</th></tr></thead><tbody><tr><td>wrote an item by hand, no metadata comment</td><td>fine — <code>owner</code>/<code>source_conv</code>/<code>ts</code> are <code>None</code></td></tr><tr><td>duplicated a <code>##</code> heading</td><td>last occurrence wins; collapses on next write</td></tr><tr><td>left prose above the first <code>##</code></td><td>ignored (file title/preamble belongs to no item)</td></tr><tr><td>malformed metadata comment</td><td>treated as content, not an error</td></tr><tr><td>renamed/deleted a link target</td><td>link dangles: skipped at expansion, reported in <code>unresolved_links</code></td></tr></tbody></table><p>Writing is the strict side: every mutation validates names, rewrites the whole category file via temp file + atomic <code>os.replace</code>, and appends a journal line. Removing a category&#39;s last item deletes the file.</p><div class="warning custom-block"><p class="custom-block-title">Out-of-band edits</p><p>Hand edits don&#39;t bump the store&#39;s revision counter — a running <code>MemoryIndex</code> won&#39;t see them until you call <code>rebuild()</code> (or restart the process; the index is in-memory and rebuilt at startup anyway).</p></div><h2 id="wiki-link-syntax" tabindex="-1">Wiki-link syntax <a class="header-anchor" href="#wiki-link-syntax" aria-label="Permalink to &quot;Wiki-link syntax&quot;">​</a></h2><p><code>[[category:name]]</code> inside item content. Category is everything up to the <strong>first</strong> colon; neither side may contain <code>[</code>, <code>]</code>, <code>:</code> or a newline; surrounding whitespace is trimmed; malformed links are ignored by the parser. Rationale and behavior: <a href="/wikimem/guide/wiki-links.html">Wiki-links</a>.</p><h2 id="journal-jsonl" tabindex="-1">journal.jsonl <a class="header-anchor" href="#journal-jsonl" aria-label="Permalink to &quot;journal.jsonl&quot;">​</a></h2><p>One JSON object per line, appended on every mutation — <code>tail -f journal.jsonl</code> is the live answer to &quot;what happened to my memory&quot;:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-10T03:00:00+00:00&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;add&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preferences&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;likes-the-sea&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;owner&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user:xnne&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;source_conv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conv_20260710&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-10T03:05:12+00:00&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;update&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preferences&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;likes-the-sea&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;owner&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user:xnne&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-10T04:11:40+00:00&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;remove&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;daily_life&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;beach-trip-plan&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>field</th><th>present</th><th>meaning</th></tr></thead><tbody><tr><td><code>ts</code></td><td>always</td><td>ISO-8601 UTC, second precision</td></tr><tr><td><code>action</code></td><td>always</td><td><code>add</code> | <code>update</code> (same-name replace) | <code>remove</code></td></tr><tr><td><code>category</code>, <code>item</code></td><td>always</td><td>what was touched</td></tr><tr><td><code>owner</code>, <code>source_conv</code>, <code>detail</code></td><td>when provided</td><td>provenance / free-form note</td></tr></tbody></table><p>Non-ASCII is stored raw (<code>ensure_ascii=False</code>) — the journal is meant to be read in a pager, not decoded.</p><h2 id="vector-cache-embed-extra" tabindex="-1">Vector cache (<code>[embed]</code> extra) <a class="header-anchor" href="#vector-cache-embed-extra" aria-label="Permalink to &quot;Vector cache (\`[embed]\` extra)&quot;">​</a></h2><p>Derived state with one nuance: vectors cost embedding-API money to recompute, so unlike the BM25 index they are cached persistently — but they are still <strong>never the source of truth</strong>, and deleting both files is always safe.</p><h3 id="vectors-keys-jsonl" tabindex="-1"><code>vectors.keys.jsonl</code> <a class="header-anchor" href="#vectors-keys-jsonl" aria-label="Permalink to &quot;\`vectors.keys.jsonl\`&quot;">​</a></h3><p>Plain text, so <em>what maps to what</em> stays readable:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;vectors_file&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vectors-000003.npy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preferences&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;likes-the-sea&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;hash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;9f8a…&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;daily_life&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;beach-trip-plan&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;hash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;b774…&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Header line names the current matrix file; then one line per row, in matrix row order. <code>hash</code> is the sha256 of the embedded text (<code>name\\ncontent</code>) — the key that makes syncs incremental (unchanged hash = no API call).</p><h3 id="vectors-nnnnnn-npy" tabindex="-1"><code>vectors-NNNNNN.npy</code> <a class="header-anchor" href="#vectors-nnnnnn-npy" aria-label="Permalink to &quot;\`vectors-NNNNNN.npy\`&quot;">​</a></h3><p>Float32 matrix, one row per key line, loaded memory-mapped. The counter suffix exists because <strong>Windows forbids replacing a file that a live index still memory-maps</strong> — each sync writes a new version and removes old ones best-effort (leftovers are swept by later syncs).</p><p>Torn state — keys file without matrix, or row-count mismatch — is treated as &quot;no cache&quot; and rebuilt on the next sync. Corruption is never trusted.</p>`,34)])])}const E=s(n,[["render",o]]);export{c as __pageData,E as default};
